int32_t hb_clf_predict(const int16_t *features, int32_t features_length) {

        int32_t votes[2] = {0,};
        int32_t _class = -1;

        _class = hb_clf_tree_0(features, features_length); votes[_class] += 1;
    _class = hb_clf_tree_1(features, features_length); votes[_class] += 1;
    _class = hb_clf_tree_2(features, features_length); votes[_class] += 1;
    _class = hb_clf_tree_3(features, features_length); votes[_class] += 1;
    _class = hb_clf_tree_4(features, features_length); votes[_class] += 1;
    _class = hb_clf_tree_5(features, features_length); votes[_class] += 1;
    _class = hb_clf_tree_6(features, features_length); votes[_class] += 1;
    _class = hb_clf_tree_7(features, features_length); votes[_class] += 1;
    _class = hb_clf_tree_8(features, features_length); votes[_class] += 1;
    _class = hb_clf_tree_9(features, features_length); votes[_class] += 1;
    
        int32_t most_voted_class = -1;
        int32_t most_voted_votes = 0;
        for (int32_t i=0; i<2; i++) {

            if (votes[i] > most_voted_votes) {
                most_voted_class = i;
                most_voted_votes = votes[i];
            }
        }
        return most_voted_class;
    }
    

int hb_clf_predict_proba(const int16_t *features, int32_t features_length, float *out, int out_length) {

        int32_t _class = -1;

        for (int i=0; i<out_length; i++) {
            out[i] = 0.0f;
        }

        _class = hb_clf_tree_0(features, features_length); out[_class] += 1.0f;
    _class = hb_clf_tree_1(features, features_length); out[_class] += 1.0f;
    _class = hb_clf_tree_2(features, features_length); out[_class] += 1.0f;
    _class = hb_clf_tree_3(features, features_length); out[_class] += 1.0f;
    _class = hb_clf_tree_4(features, features_length); out[_class] += 1.0f;
    _class = hb_clf_tree_5(features, features_length); out[_class] += 1.0f;
    _class = hb_clf_tree_6(features, features_length); out[_class] += 1.0f;
    _class = hb_clf_tree_7(features, features_length); out[_class] += 1.0f;
    _class = hb_clf_tree_8(features, features_length); out[_class] += 1.0f;
    _class = hb_clf_tree_9(features, features_length); out[_class] += 1.0f;
    
        // compute mean
        for (int i=0; i<out_length; i++) {
            out[i] = out[i] / 10;
        }
        return 0;
    }
    

// ==========================================================================
//  REGRESSION INFERENCE  (with skin-tone correction)
// ==========================================================================

static inline float hb_reg_calibrate(float hb_raw, uint8_t skin_group) {
    float slope, intercept;
    if (skin_group == 1) {
        slope     = 0.964850f;
        intercept = 0.517685f;
    } else if (skin_group == 3) {
        slope     = 1.000000f;
        intercept = 0.000000f;
    } else {
        slope     = 1.064948f;
        intercept = -0.876066f;
    }
    float out = slope * hb_raw + intercept;
    if (out < 6.0f)  out = 6.0f;
    if (out > 20.0f) out = 20.0f;
    return out;
}

// ==========================================================================
//  COMBINED DUAL INFERENCE  — call this from your firmware loop
// ==========================================================================

/**
 * hb_dual_predict()
 *
 * @param features  int16_t array[HB_N_FEATURES] — raw feature values × 1000
 *                  features[0]  = demo_sex × 1000  (1000=male, 0=female)
 *                  features[1]  = demo_age × 1000
 *                  features[2]  = mi_530_940 × 1000   (DC_530/DC_940)
 *                  ... (see feature order in header comment)
 * @param sex_male  1 = male, 0 = female  (for WHO threshold selection)
 * @return          HbResult struct
 *
 * USAGE EXAMPLE (ESP32 Arduino):
 *   int16_t feat[HB_N_FEATURES];
 *   feat[0]  = (int16_t)(demo_sex  * 1000);
 *   feat[1]  = (int16_t)(demo_age  * 1000);
 *   feat[2]  = (int16_t)(mi_530_940 * 1000);
 *   // ... fill remaining features ...
 *   HbResult r = hb_dual_predict(feat, HB_N_FEATURES, 1);
 *   Serial.printf("Hb=%.2f  Anemia=%d\n", r.hb_calibrated, r.anemia_flag);
 */
static inline HbResult hb_dual_predict(const int16_t *features,
                                        int32_t features_length,
                                        uint8_t sex_male) {

    HbResult result;

    // ── 1. Skin-tone group from mi_530_940 (feature[2]) ──────────────────
    int16_t mi_raw  = features[2];
    if      (mi_raw < HB_SKIN_THR_LOW)   result.skin_group = 1;
    else if (mi_raw < HB_SKIN_THR_HIGH)  result.skin_group = 2;
    else                                  result.skin_group = 3;

    // ── 2. Regression ─────────────────────────────────────────────────────
    result.hb_raw        = hb_reg_predict(features, features_length);
    result.hb_calibrated = hb_reg_calibrate(result.hb_raw, result.skin_group);

    // ── 3. Classification ─────────────────────────────────────────────────
    // emlearn classifier returns probability directly for binary case
    float clf_raw        = hb_clf_predict(features, features_length);
    // Normalise to [0,1]  (emlearn binary returns 0 or 1 per tree vote)
    result.anemia_prob   = clf_raw;   // already averaged votes
    float thr            = (float)HB_CLF_THRESHOLD / 1000.0f;
    result.anemia_flag   = (result.anemia_prob >= thr) ? 1 : 0;

    // ── 4. WHO cross-check (regression-based safety net) ─────────────────
    float who_thr = sex_male ? 13.0f : 12.0f;
    if (result.hb_calibrated < who_thr && result.anemia_flag == 0) {
        // Regression says anemic, classifier said no — flag it
        result.anemia_flag = 1;
    }

    // ── 5. Confidence: distance from WHO threshold ────────────────────────
    float dist = result.hb_calibrated - who_thr;
    if (dist < 0) dist = -dist;
    if      (dist > 2.0f) result.confidence = 2;  // High
    else if (dist > 1.0f) result.confidence = 1;  // Medium
    else                  result.confidence = 0;  // Low (near boundary)

    return result;
}

